              combo = comboTimer > 0 ? combo + 1 : 1;
              comboTimer = 1.2;

              if (combo >= 3) {
                const bonus = combo * 2;
                score += bonus;
                addFloatingText('连击 +' + bonus, enemy.x, enemy.y, '#f6ad55');
              }

              createExplosion(enemy.x, enemy.y, enemy.color, enemy.type === 'big' ? 24 : 14);
              addFloatingText('+' + enemy.score, enemy.x, enemy.y);

              if (Math.random() < 0.14) {
                spawnPowerUp(enemy.x, enemy.y);
              }

              enemies.splice(j, 1);
            }

            break;
          }
        }

        if (hit) continue;
      }

      for (let i = powerUps.length - 1; i >= 0; i--) {
        const item = powerUps[i];
        item.y += item.speed * dt;
        item.pulse += dt * 5;

        if (item.y > GAME_HEIGHT + 24) {
          powerUps.splice(i, 1);
          continue;
        }

        if (rectsCollide(
          { x: player.x, y: player.y, width: player.width, height: player.height },
          { x: item.x, y: item.y, width: item.width, height: item.height }
        )) {
          if (item.type === 'double') {
            player.doubleShot = true;
            player.doubleShotTimer = 7;
            addFloatingText('双发射击', item.x, item.y, '#4fd1c5');
          } else {
            player.shield = true;
            player.shieldTimer = 6;
            addFloatingText('护盾启动', item.x, item.y, '#63b3ed');
          }
          createExplosion(item.x, item.y, item.type === 'double' ? '#4fd1c5' : '#63b3ed', 12);
          powerUps.splice(i, 1);
        }
      }

      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        p.life -= dt;
        p.vx *= 0.98;
        p.vy *= 0.98;

        if (p.life <= 0) particles.splice(i, 1);
      }

      for (let i = floatingTexts.length - 1; i >= 0; i--) {
        const t = floatingTexts[i];
        t.y -= 26 * dt;
        t.life -= dt;
        if (t.life <= 0) floatingTexts.splice(i, 1);
      }

      if (score > highScore) {
        highScore = score;
        localStorage.setItem('planeWarHighScore', String(highScore));
      }
    }

    function drawRoundedRect(x, y, w, h, r, fillStyle, strokeStyle = null) {
      ctx.beginPath();
      ctx.moveTo(x + r, y);
      ctx.arcTo(x + w, y, x + w, y + h, r);
      ctx.arcTo(x + w, y + h, x, y + h, r);
      ctx.arcTo(x, y + h, x, y, r);
      ctx.arcTo(x, y, x + w, y, r);
      ctx.closePath();
      if (fillStyle) {
        ctx.fillStyle = fillStyle;
        ctx.fill();
      }
      if (strokeStyle) {
        ctx.strokeStyle = strokeStyle;
        ctx.stroke();
      }
    }

    function drawPlayer() {
      ctx.save();
      ctx.translate(player.x, player.y);

      if (flashTimer > 0) {
        ctx.globalAlpha = 0.65 + Math.sin(flashTimer * 50) * 0.35;
      }

      ctx.fillStyle = '#4fd1c5';
      ctx.beginPath();
      ctx.moveTo(0, -22);
      ctx.lineTo(14, 18);
      ctx.lineTo(4, 12);
      ctx.lineTo(0, 20);
      ctx.lineTo(-4, 12);
      ctx.lineTo(-14, 18);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = '#e2e8f0';
      ctx.beginPath();
      ctx.moveTo(0, -10);
      ctx.lineTo(6, 10);
      ctx.lineTo(0, 6);
      ctx.lineTo(-6, 10);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = '#90cdf4';
      ctx.beginPath();
      ctx.arc(0, -5, 4, 0, Math.PI * 2);
      ctx.fill();

      if (player.shield) {
        ctx.strokeStyle = 'rgba(99, 179, 237, 0.8)';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.arc(0, 0, 28 + Math.sin(performance.now() * 0.01) * 2, 0, Math.PI * 2);
        ctx.stroke();
      }

      ctx.restore();
    }

    function drawEnemy(enemy) {
      ctx.save();
      ctx.translate(enemy.x, enemy.y);
      ctx.fillStyle = enemy.color;

      if (enemy.type === 'small') {
        ctx.beginPath();
        ctx.moveTo(0, 16);
        ctx.lineTo(12, -10);
        ctx.lineTo(0, -15);
        ctx.lineTo(-12, -10);
        ctx.closePath();
        ctx.fill();
      } else if (enemy.type === 'medium') {
        ctx.beginPath();
        ctx.moveTo(0, 20);
        ctx.lineTo(16, 2);
        ctx.lineTo(12, -16);
        ctx.lineTo(0, -20);
        ctx.lineTo(-12, -16);
        ctx.lineTo(-16, 2);
        ctx.closePath();
        ctx.fill();
      } else {
        ctx.beginPath();
        ctx.moveTo(0, 26);
        ctx.lineTo(20, 14);
        ctx.lineTo(22, -10);
        ctx.lineTo(10, -24);
        ctx.lineTo(-10, -24);
        ctx.lineTo(-22, -10);
        ctx.lineTo(-20, 14);
        ctx.closePath();
        ctx.fill();

        ctx.fillStyle = 'rgba(255,255,255,0.15)';
        ctx.fillRect(-10, -8, 20, 6);
      }

      if (enemy.maxHp > 1) {
        ctx.fillStyle = 'rgba(255,255,255,0.16)';
        ctx.fillRect(-enemy.width / 2, enemy.height / 2 + 6, enemy.width, 4);
        ctx.fillStyle = '#4fd1c5';
        ctx.fillRect(-enemy.width / 2, enemy.height / 2 + 6, enemy.width * (enemy.hp / enemy.maxHp), 4);
      }

      ctx.restore();
    }

    function renderBackground() {
      const bg = ctx.createLinearGradient(0, 0, 0, GAME_HEIGHT);
      bg.addColorStop(0, '#1a1a2e');
      bg.addColorStop(1, '#16213e');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

      for (const s of stars) {
        ctx.globalAlpha = s.alpha;
        ctx.fillStyle = '#ffffff';
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.globalAlpha = 1;

      ctx.strokeStyle = 'rgba(79, 209, 197, 0.08)';
      ctx.lineWidth = 1;
      for (let y = 0; y < GAME_HEIGHT; y += 80) {
        ctx.beginPath();
        ctx.moveTo(20, y);
        ctx.lineTo(GAME_WIDTH - 20, y + 40);
        ctx.stroke();
      }
    }

    function renderHUD() {
      ctx.textAlign = 'center';
      ctx.textBaseline = 'top';

      drawRoundedRect(95, 10, 170, 52, 12, 'rgba(255,255,255,0.08)', 'rgba(255,255,255,0.08)');

      ctx.fillStyle = '#ffffff';
      ctx.font = '14px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('得分', GAME_WIDTH / 2, 18);

      ctx.fillStyle = '#4fd1c5';
      ctx.font = 'bold 24px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(score, GAME_WIDTH / 2, 32);

      ctx.textAlign = 'left';
      ctx.fillStyle = '#ffffff';
      ctx.font = '12px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('最高分', 16, 18);
      ctx.fillStyle = '#4fd1c5';
      ctx.font = 'bold 16px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(highScore, 16, 34);

      ctx.textAlign = 'right';
      ctx.fillStyle = '#ffffff';
      ctx.font = '12px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('生命', GAME_WIDTH - 16, 18);

      for (let i = 0; i < player.maxHp; i++) {
        ctx.fillStyle = i < player.hp ? '#f56565' : 'rgba(255,255,255,0.18)';
        const x = GAME_WIDTH - 16 - (player.maxHp - 1 - i) * 16;
        const y = 40;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.arc(x - 4, y - 4, 4, 0, Math.PI, true);
        ctx.arc(x + 4, y - 4, 4, 0, Math.PI, true);
        ctx.lineTo(x, y + 8);
        ctx.closePath();
        ctx.fill();
      }

      let statusX = 16;
      let statusY = 76;

      if (player.doubleShot) {
        drawRoundedRect(statusX, statusY, 78, 26, 12, 'rgba(79, 209, 197, 0.14)', 'rgba(79, 209, 197, 0.2)');
        ctx.fillStyle = '#4fd1c5';
        ctx.textAlign = 'left';
        ctx.font = '12px PingFang SC, Microsoft YaHei, sans-serif';
        ctx.fillText('双发 ' + player.doubleShotTimer.toFixed(1) + 's', statusX + 10, statusY + 6);
        statusY += 32;
      }

      if (player.shield) {
        drawRoundedRect(statusX, statusY, 78, 26, 12, 'rgba(99, 179, 237, 0.14)', 'rgba(99, 179, 237, 0.2)');
        ctx.fillStyle = '#63b3ed';
        ctx.fillText('护盾 ' + player.shieldTimer.toFixed(1) + 's', statusX + 10, statusY + 6);
      }

      if (comboTimer > 0 && combo >= 2) {
        ctx.textAlign = 'center';
        ctx.fillStyle = '#f6ad55';
        ctx.font = 'bold 16px PingFang SC, Microsoft YaHei, sans-serif';
        ctx.fillText(combo + ' 连击', GAME_WIDTH / 2, 76);
      }
    }

    function renderOverlay(title, subtitle, hint) {
      ctx.fillStyle = 'rgba(0,0,0,0.42)';
      ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

      drawRoundedRect(36, 182, 288, 220, 12, 'rgba(255,255,255,0.08)', 'rgba(255,255,255,0.10)');

      ctx.textAlign = 'center';
      ctx.fillStyle = '#ffffff';
      ctx.font = 'bold 30px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(title, GAME_WIDTH / 2, 225);

      ctx.fillStyle = '#4fd1c5';
      ctx.font = 'bold 17px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(subtitle, GAME_WIDTH / 2, 276);

      ctx.fillStyle = 'rgba(255,255,255,0.88)';
      ctx.font = '14px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(hint, GAME_WIDTH / 2, 325);

      ctx.fillStyle = 'rgba(255,255,255,0.68)';
      ctx.font = '12px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('键盘：方向键 / WASD 移动，空格射击，P 暂停', GAME_WIDTH / 2, 358);
      ctx.fillText('触屏：拖动左侧摇杆，点击开火/暂停', GAME_WIDTH / 2, 380);
    }

    function render() {
      renderBackground();

      for (const bullet of bullets) {
        ctx.fillStyle = '#4fd1c5';
        ctx.shadowColor = '#4fd1c5';
        ctx.shadowBlur = 8;
        drawRoundedRect(bullet.x - bullet.width / 2, bullet.y - bullet.height / 2, bullet.width, bullet.height, 3, '#4fd1c5');
        ctx.shadowBlur = 0;
      }

      for (const enemy of enemies) {
        drawEnemy(enemy);
      }

      for (const item of powerUps) {
        ctx.save();
        ctx.translate(item.x, item.y);
        const scale = 1 + Math.sin(item.pulse) * 0.08;
        ctx.scale(scale, scale);

        const color = item.type === 'double' ? '#4fd1c5' : '#63b3ed';
        ctx.fillStyle = color;
        ctx.shadowColor = color;
        ctx.shadowBlur = 12;
        ctx.beginPath();
        ctx.arc(0, 0, 11, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;

        ctx.fillStyle = '#0f172a';
        ctx.font = 'bold 12px PingFang SC, Microsoft YaHei, sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(item.type === 'double' ? 'D' : 'S', 0, 1);
        ctx.restore();
      }

      for (const p of particles) {
        ctx.globalAlpha = Math.max(0, p.life / p.maxLife);
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.globalAlpha = 1;

      if (player.alive || gameState !== 'gameover') {
        drawPlayer();
      }

      for (const t of floatingTexts) {
        ctx.globalAlpha = Math.max(0, t.life / t.maxLife);
        ctx.fillStyle = t.color;
        ctx.font = 'bold 14px PingFang SC, Microsoft YaHei, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(t.text, t.x, t.y);
      }
      ctx.globalAlpha = 1;

      renderHUD();

      if (gameState === 'menu') {
        renderOverlay('飞机大战', '最高分 ' + highScore, '点击屏幕或按 Enter 开始');
      } else if (gameState === 'paused') {
        renderOverlay('已暂停', '当前得分 ' + score, '点击屏幕或按 Enter / P 继续');
      } else if (gameState === 'gameover') {
        renderOverlay('游戏结束', '本局得分 ' + score, '点击屏幕或按 Enter 重新开始');
      }
    }

    function gameLoop(timestamp) {
      const deltaTime = (timestamp - lastTime) / 1000 || 0;
      lastTime = timestamp;

      update(deltaTime);
      render();

      requestAnimationFrame(gameLoop);
    }

    resetGame();
    gameState = 'menu';
    requestAnimationFrame(gameLoop);
  </script>
